import{a as e}from"./chunk-KSMC2BDF.js";import"./chunk-IFGU66OU.js";var t={meta:e,sections:[{id:"overview",title:"Overview",blocks:[{type:"markdown",value:"**Blue-Green Deployment** runs two near-identical environments: **Blue** (current production) and **Green** (new version). After Green is validated, traffic switches atomically to Green. Rollback is switching back to Blue."},{type:"callout",variant:"info",title:"Goal",body:"**Zero-downtime** releases with a simple, fast rollback path \u2014 at the cost of roughly **2\xD7** peak capacity during cutover."}]},{id:"concept",title:"Concept and analogy",blocks:[{type:"callout",variant:"tip",title:"Real-world analogy",body:"A theater with **two stages**: the audience watches Blue while Green is set up behind the curtain. When ready, lights switch to Green. If something is wrong, switch back."},{type:"mermaid",caption:"Atomic cutover via load balancer.",definition:`flowchart LR
  Users --> LB[Load Balancer]
  LB -->|active| Blue[Blue v1]
  LB -.->|idle| Green[Green v2]
  Note1[After validation: flip LB to Green]`}]},{id:"where-used",title:"Where it is used",blocks:[{type:"table",headers:["Domain","Example"],rows:[["Cloud LBs","Swap target group / backend pool"],["Kubernetes","Two Deployments + Service selector flip"],["PaaS","Heroku / Cloud Foundry style release slots"],["Databases*","App cutover; schema needs expand/contract care"],["Regulated releases","When instant rollback is mandatory"]]},{type:"callout",variant:"warning",title:"Data plane caveat",body:"Blue-green is easy for **stateless** services. Shared databases need **backward-compatible migrations** (expand/contract) or both colors cannot safely share the schema."}]},{id:"implementation",title:"Implementation",blocks:[{type:"markdown",value:"Operational checklist (platform-agnostic):"},{type:"timeline",items:[{title:"Deploy Green",description:"Ship v2 alongside Blue; do not send user traffic yet.",meta:"Step 1"},{title:"Smoke / soak",description:"Run health checks, synthetic tests, maybe mirrored traffic.",meta:"Step 2"},{title:"Flip router",description:"Point LB/DNS/Service selector to Green atomically.",meta:"Step 3"},{title:"Observe + keep Blue warm",description:"Watch error/latency; keep Blue ready for instant rollback.",meta:"Step 4"},{title:"Decommission Blue",description:"After confidence window, recycle Blue as the next Green.",meta:"Step 5"}]},{type:"prosCons",title:"Trade-offs",pros:["Simple mental model and fast rollback.","Near zero downtime for stateless apps.","Easy to reason about in incident response."],cons:["Needs roughly double capacity during transition.","Harder with incompatible DB schema changes.","Long-lived dual environments increase cost."]}]},{id:"interview-questions",title:"Interview Questions",blocks:[{type:"interviewQa",items:[{question:"Explain blue-green deployment.",answer:"Run two parallel environments; validate the new one (Green), then **switch all traffic** from Blue to Green. Rollback = switch back."},{question:"Blue-green vs canary?",answer:"Blue-green is usually an **all-or-nothing cutover**. Canary sends a **small percentage** first and ramps up. Canary reduces blast radius; blue-green optimizes for simplicity and instant flip."},{question:"Blue-green vs rolling update?",answer:"Rolling replaces pods gradually in one environment. Blue-green keeps two full environments and flips the router. Rolling uses less spare capacity but rollback can be slower/messier."},{question:"What about database migrations?",answer:"Use **expand/contract**: additive compatible changes first, deploy app, then remove old columns later. Never deploy a breaking schema only Green understands while Blue still runs."},{question:"When would you choose blue-green?",answer:"When you can afford spare capacity and want the simplest zero-downtime + rollback story for mostly stateless services."}]}]},{id:"summary",title:"Summary",blocks:[{type:"callout",variant:"summary",title:"Key takeaways",body:`1. Two environments \u2192 validate \u2192 **atomic switch**.
2. Rollback is flipping traffic back.
3. Real uses: **LB cutovers, K8s dual deployments**.
4. Plan **compatible migrations**; compare with canary/rolling.`}]}]},n=t;export{n as default};
